// Pega os dados do JSON
let offerCode = $node["Webhook"].json["body"]["data"]["purchase"]["offer"];
let Plan="Plano Starter 1";
let PlanId=2;

switch (offerCode.code){
  // case "kgbwfq3o":PlanId=1;Plan="Plano Starter 1";break;
  case "9icexive":PlanId=2;Plan="Plano Starter 2";break;
  case "0m008nnk":PlanId=2;Plan="Plano Starter 2";break;
  case "eeiyi1s4":PlanId=5;Plan="Plano PRO 10";break;
  case "lkt5vvav":PlanId=4;Plan="Plano Elite";break;
  //case "0m008nnk":PlanId=6;Plan="Plano Starter 5";break;
  case "o4n30uxc":PlanId=6;Plan="Plano PRO 6Whats";break;
  default:PlanId=2;
}

return [{ json: { PlanId: PlanId,Plan: Plan } }];

